class Solution:
    def minimumDifference(self, nums: List[int], k: int) -> int:
        min_diff = float('inf')
        current_ors = set()

        for num in nums:
            new_ors = set()
            new_ors.add(num)
            for val in current_ors:
                new_ors.add(val | num)
            current_ors = new_ors
            for val in current_ors:
                min_diff = min(min_diff, abs(val - k))

        return min_diff
